const corsPlugin: FastifyPluginAsync = async (fastify) => {
  const origins = fastify.config.CORS_ORIGIN.split(',').map((origin) => origin.trim());

  await fastify.register(fastifyCors, {
    origin: origins,
    credentials: fastify.config.CORS_CREDENTIALS,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
    exposedHeaders: ['X-Request-Id'],
  });
};

return async <T extends FastifyRequest, U extends FastifyReply>(request: T, reply: U) => {
  const users = app.mongo.db?.collection('users');
  const roles = app.mongo.db?.collection('roles');

  const user = await users?.findOne(
    { username: { $eq: request.user.username } },
    { projection: { password: 0, secret: 0 } },
  );

  const role = await roles?.findOne(
    { userId: { $ref: 'users', $id: user?._id } },
    { projection: { role: 1, permissions: 1 } },
  );

  if (role?.role !== 'admin') return reply.forbidden();
};

export const jsonSchemaToOAS = (
  jsonSchema: JSONSchema.BaseSchema,
  oasVersion: OASVersion,
): OpenAPIV3.SchemaObject | OpenAPIV3_1.SchemaObject => {
  switch (oasVersion) {
    case '3.0':
      return jsonSchemaToOAS_3_0(jsonSchema)
    case '3.1':
      return jsonSchemaToOAS_3_1(jsonSchema)
    default:
      throw new Error(`Unsupported OpenAPI version: ${oasVersion}`)
  }
}

export const replacePathPrefix = <T extends string>(
  prevPrefixPath: T[],
  nextPrefixPath: T[],
  path: T[],
): T[] => {
  if (!matchPathPrefix(prevPrefixPath, path)) {
    throw new Error(
      `path='${stringifyPath(
        path,
      )}' doesn't match prevPrefixPath='${stringifyPath(prevPrefixPath)}'`,
    );
  }
  return [...nextPrefixPath, ...path.slice(prevPrefixPath.length)];
};

